import os
import json
import time
import requests
import pickle
from datetime import datetime, timedelta


class CacheItem:
    def __init__(self, value, expiry):
        self.value = value
        self.expiry = expiry

    def is_expired(self):
        return datetime.now() > self.expiry


class Cache:
    def __init__(self, max_age):
        self.max_age = max_age
        self.cache = {}

    def get(self, key):
        if key in self.cache and not self.cache[key].is_expired():
            return self.cache[key].value
        else:
            return None

    def set(self, key, value):
        self.cache[key] = CacheItem(value, datetime.now() + timedelta(seconds=self.max_age))

    def save(self, filename):
        with open(filename, 'wb') as f:
            pickle.dump(self.cache, f)

    def load(self, filename):
        if os.path.exists(filename):
            with open(filename, 'rb') as f:
                self.cache = pickle.load(f)


def api_request(url, cache):
    response = cache.get(url)
    
    if response is None:
        response = requests.get(url).json()
        cache.set(url, response)

    return response

cache = Cache(max_age=60)
cache.load('cache.pkl')

response = api_request('http://example.com/api', cache)

